import React, { useState, useEffect } from 'react';

const App = () => {
  const [typedText, setTypedText] = useState('');
  const [showContent, setShowContent] = useState(false);
  const [currentLine, setCurrentLine] = useState(0);

  const commands = [
    'zenu@dev:~$ npm run start-portfolio...',
    'zenu@dev:~$ loading developer profile...',
    'zenu@dev:~$ initializing tech stack...',
    'zenu@dev:~$ profile loaded successfully ✓'
  ];

  const techStack = [
    'JavaScript',
    'Swift',
    'Kotlin',
    'Node.js',
    'React',
    'Jetpack Compose',
    'SwiftUI',
    'MongoDB',
    'Firebase'
  ];

  useEffect(() => {
    let timeout;
    let charIndex = 0;
    let lineIndex = 0;

    const typeNextChar = () => {
      if (lineIndex < commands.length) {
        const currentCommand = commands[lineIndex];

        if (charIndex < currentCommand.length) {
          setTypedText(prev => {
            const lines = prev.split('\n');
            if (lines.length <= lineIndex) {
              lines.push('');
            }
            lines[lineIndex] = currentCommand.substring(0, charIndex + 1);
            return lines.join('\n');
          });
          charIndex++;
          timeout = setTimeout(typeNextChar, 50 + Math.random() * 50);
        } else {
          charIndex = 0;
          lineIndex++;
          timeout = setTimeout(typeNextChar, 400);
        }
      } else {
        setShowContent(true);
      }
    };

    typeNextChar();

    return () => clearTimeout(timeout);
  }, []);

  return (
    <div className="terminal-container">
      <div className="terminal-window">
        <div className="terminal-header">
          <div className="terminal-buttons">
            <div className="terminal-button close"></div>
            <div className="terminal-button minimize"></div>
            <div className="terminal-button maximize"></div>
          </div>
          <div className="terminal-title">zenu@dev:~</div>
        </div>
        <div className="terminal-body">
          <div className="terminal-output">
            <pre className="typing-text">{typedText}</pre>
            <span className="cursor">█</span>
          </div>

          {showContent && (
            <div className="terminal-content fade-in">
              <div className="welcome-section">
                <h1 className="greeting">
                  <span className="prompt">zenu@dev:~$</span> whoami
                </h1>
                <p className="developer-name">
                  <span className="accent">→</span> Hamzah Mohandeszade (Zenu)
                </p>
                <p className="developer-title">Full Stack Developer</p>
              </div>

              <div className="section">
                <h2 className="section-title">
                  <span className="prompt">zenu@dev:~$</span> cat tech-stack.txt
                </h2>
                <div className="tech-grid">
                  {techStack.map((tech, index) => (
                    <div key={index} className="tech-item">
                      <span className="tech-bullet">▸</span>
                      {tech}
                    </div>
                  ))}
                </div>
              </div>

              <div className="section">
                <h2 className="section-title">
                  <span className="prompt">zenu@dev:~$</span> ls -la contact/
                </h2>
                <div className="contact-links">
                  <a href="#" className="contact-link">
                    <span className="path">./github</span>
                  </a>
                  <a href="#" className="contact-link">
                    <span className="path">./linkedin</span>
                  </a>
                  <a href="#" className="contact-link">
                    <span className="path">./email</span>
                  </a>
                </div>
              </div>

              <div className="terminal-footer">
                <span className="prompt">zenu@dev:~$</span>
                <span className="cursor">█</span>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;
